import torch
import torch.nn as nn

class DistogramHead(nn.Module):
    def __init__(self, d_pair=128, num_bins=64):
        super().__init__()
        self.linear = {{prot_struct_disto_b1}}

    def forward(self, pair_repr):
        # pair_repr: (L, L, d_pair)
        logits = self.linear(pair_repr)  # (L, L, num_bins)
        # Symmetrize: average (i,j) and (j,i)
        logits = (logits + {{prot_struct_disto_b2}}) / 2
        return torch.softmax(logits, dim=-1)

